#include <bits/stdc++.h>
#define x first
#define dis second
using namespace std;
typedef pair<int,int> pii;

const int N=1e4+10,V=1e7+10;

int n,m,q[110],f[N],sz[N];
bool ans[110],b[N],v[V];
vector<pii> g[N];
queue<int> st,s;

void dfs(int x,int fa){
    f[x]=fa;
    sz[x]=1;
    for(pii y:g[x])
        if(y.x!=fa && !b[y.x]){
            dfs(y.x,x);
            sz[x]+=sz[y.x];
        }
}

int Balance(int x,int S){
    if(S-sz[x]>S/2)
        return Balance(f[x],S);
    for(pii y:g[x])
        if(y.x!=f[x] && !b[y.x] && sz[y.x]>S/2)
            return Balance(y.x,S);
    return x;
}

void dfs2(int x,int dis){
    if(dis>1e7)
        return;
//    printf("to %d %d\n",x,dis);
    for(int i=1;i<=m;i++)
        if(dis<=q[i] && v[q[i]-dis])
            ans[i]=true;
    s.push(dis);
    for(pii y:g[x])
        if(!b[y.x] && y.x!=f[x])
            dfs2(y.x,dis+y.dis);
}

void solve(int x){
    dfs(x,0);
    x=Balance(x,sz[x]);
    dfs(x,0);
//    printf("%d\n",x);
    v[0]=1;
    st.push(0);
    for(pii y:g[x])
        if(!b[y.x]){
            dfs2(y.x,y.dis);
            while(s.size()){
                if(!v[s.front()]){
                    v[s.front()]=true;
                    st.push(s.front());
                }
                s.pop();
            }
        }
    while(st.size()){
        v[st.front()]=false;
        st.pop();
    }
    b[x]=1;
    for(pii y:g[x])
        if(!b[y.x])
            solve(y.x);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1,u,v,w;i<n;i++){
        scanf("%d%d%d",&u,&v,&w);
        g[u].push_back(make_pair(v,w));
        g[v].push_back(make_pair(u,w));
    }
    for(int i=1;i<=m;i++)
        scanf("%d",&q[i]);
    solve(1);
    for(int i=1;i<=m;i++)
        if(ans[i])
            puts("AYE");
        else
            puts("NAY");
    return 0;
}
